mapper.select:
/* oms-report-inXOutboundList-sql-oracle.xml selectInXOutboundCount */
SELECT COUNT(1)
FROM TORDER_INFO_SO_HD A
LEFT OUTER JOIN TORDER_INFO_CO_HD B
  ON A.OWKEY = B.OWKEY
 AND A.CUSTOMERORDERKEY = B.CUSTOMERORDERKEY

	INNER JOIN (
		SELECT MAX(X.SO_HDKEY) AS SO_HDKEY /*S/O번호*/
			 , X.OWKEY
		FROM TORDER_INFO_SO_DT X
		WHERE X.OWKEY = #{owkey}
		  AND X.OR_HDDATE BETWEEN #{orHddateFr} AND  #{orHddateTo}
		  AND X.ICKEY IN

		#{ickey}

	GROUP BY X.OWKEY, X.SO_HDKEY
	) IC
	ON A.OWKEY = IC.OWKEY AND A.SO_HDKEY = IC.SO_HDKEY



		AND #{SEARCH_CONDITION}


		AND  A.OR_TYPE_CD IN

			#{orType}



		AND  A.WKSTATUS != #{cancelYn}


		AND  A.WKSTATUS = #{cancelYn}

/* oms-report-inXOutboundList-sql-oracle.xml selectInXOutboundList */ #{GRIDPAGING_ROWNUMTYPE_TOP} SELECT A.SO_HDKEY , A.WKSTATUS AS SOSTATUS , CASE WHEN COALESCE(B.SAPTRANSFAILYN, 'N') <> 'N' THEN 'NONCOMPLETE' WHEN COALESCE(B.SAPTRANSFAILYN, 'N') = 'N' AND B.WKSTATUS=#{coSendWkstatus} THEN 'COMPLETE' ELSE NULL END AS SAPTRANSFAILYN , A.OWKEY , C.OWNM , A.OR_TYPE_CD , A.OR_HDDATE , A.ACKEY , D.ACNM AS ACNAME , B.WKSTATUS AS COSTATUS , A.DELIVERY_KEY , F.ACNM AS DELIVERY_NAME , A.STORE_KEY , G.ACNM AS STORE_NAME , A.EXTERNORDERKEY , A.REF_DELIVERY_NO , B.INTERFACE_ID , A.ORDER_ERROR_CD , A.ORDER_ERROR_COMMENTS , A.INSERTDATE , A.INSERTURKEY , A.UPDATEDATE , A.UPDATEURKEY FROM TORDER_INFO_SO_HD A LEFT OUTER JOIN TORDER_INFO_CO_HD B ON A.OWKEY = B.OWKEY AND A.CUSTOMERORDERKEY = B.CUSTOMERORDERKEY LEFT OUTER JOIN TADMIN_MST_OW C ON A.OWKEY = C.OWKEY LEFT OUTER JOIN TADMIN_MST_CUSTOMER D ON A.OWKEY = D.OWKEY AND A.ACKEY = D.ACKEY LEFT OUTER JOIN TADMIN_MST_CUSTOMER F ON A.OWKEY = F.OWKEY AND A.DELIVERY_KEY = F.ACKEY LEFT OUTER JOIN TADMIN_MST_CUSTOMER G ON A.OWKEY = G.OWKEY AND A.STORE_KEY = G.ACKEY
INNER JOIN ( SELECT MAX(X.SO_HDKEY) AS SO_HDKEY /*S/O번호*/ , X.OWKEY FROM TORDER_INFO_SO_DT X WHERE X.OWKEY = #{owkey} AND X.OR_HDDATE BETWEEN #{orHddateFr} AND #{orHddateTo} AND X.ICKEY IN
#{ickey}
GROUP BY X.OWKEY, X.SO_HDKEY ) IC ON A.OWKEY = IC.OWKEY AND A.SO_HDKEY = IC.SO_HDKEY
AND #{SEARCH_CONDITION}
AND A.OR_TYPE_CD IN
#{orType}
AND A.WKSTATUS != #{cancelYn}
AND A.WKSTATUS = #{cancelYn}
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}
